            <AnimatePresence mode="wait">
                {status === "input" && renderInput()}
                {status === "history" && renderHistory()}
                {status === "generating" && renderGenerating()}
                {status === "quiz" && renderQuiz()}
                {status === "result" && renderResult()}
            </AnimatePresence>
